// Auto-generated by Oh-Ben-Claw firmware scaffold — starter sketch; edit freely.
// Board: nucleo-f401re (0483:374b)  vendor: STMicroelectronics
// Capabilities: gpio, analog_read, analog_write, i2c, spi, pwm, rtt, flash
// Node: obc-node

#include <Wire.h>
#include <SPI.h>

const char* OBC_NODE_ID = "obc-node";
const char* OBC_BOARD    = "nucleo-f401re";

// Announce this node + its capabilities to the brain over serial on boot.
void announce() {
  Serial.print("{\"type\":\"announce\",\"node_id\":\"");
  Serial.print(OBC_NODE_ID);
  Serial.print("\",\"board\":\"");
  Serial.print(OBC_BOARD);
  Serial.println("\",\"capabilities\":[\"gpio\",\"analog_read\",\"analog_write\",\"i2c\",\"spi\",\"pwm\",\"rtt\",\"flash\"]}");
}

// Handle one line-framed command from the brain.
void handleCommand(const String& cmd) {
  // TODO: parse JSON and dispatch (ping, gpio_write, sensor_read, ...).
  if (cmd.indexOf("ping") >= 0) {
    Serial.println("{\"ok\":true,\"pong\":true}");
  }
}

void setup() {
  Serial.begin(115200);
  while (!Serial) {}
  Wire.begin();
  SPI.begin();
  announce();
}

void loop() {
  if (Serial.available()) {
    String line = Serial.readStringUntil('\n');
    handleCommand(line);
  }
}

